/* ===== APPLY LANGUAGE ===== */
function applyLang(lang) {
  const dict = T[lang] || T.en;
  if (!dict) return;

  document.querySelectorAll('[data-i18n]').forEach(el => {
    const v = dict[el.dataset.i18n];
    if (v !== undefined) el.textContent = v;
  });
  document.querySelectorAll('[data-i18n-html]').forEach(el => {
    const v = dict[el.dataset.i18nHtml];
    if (v !== undefined) el.innerHTML = v;
  });
  document.querySelectorAll('[data-i18n-ph]').forEach(el => {
    const v = dict[el.dataset.i18nPh];
    if (v !== undefined) el.placeholder = v;
  });

  const page = document.documentElement.dataset.page;
  if (page && dict['title.' + page]) document.title = dict['title.' + page];
  document.documentElement.lang = lang;

  const lbl = document.getElementById('headerLangLabel');
  if (lbl) lbl.textContent = lang.toUpperCase();
}

/* ===== HEADER SWITCHER ===== */
function initHeaderSwitcher() {
  const wrap = document.getElementById('headerLangSwitch');
  const btn = document.getElementById('headerLangBtn');
  const drop = document.getElementById('headerLangDropdown');
  if (!wrap || !btn) return;

  btn.addEventListener('click', e => {
    e.stopPropagation();
    wrap.classList.toggle('open');
  });
  document.addEventListener('click', () => wrap.classList.remove('open'));

  drop.querySelectorAll('.lang-option').forEach(opt => {
    opt.addEventListener('click', () => {
      const lang = opt.dataset.lang;
      wrap.classList.remove('open');
      localStorage.setItem('lang', lang);
      document.body.classList.add('lang-changing');
      setTimeout(() => {
        applyLang(lang);
        document.body.classList.remove('lang-changing');
      }, 190);
    });
  });
}

/* ===== AUTO-DETECT LANGUAGE ===== */
function detectLang() {
  const lang = (navigator.language || navigator.userLanguage || 'en').toLowerCase().split('-')[0];
  const cis = ['ru', 'uk', 'be', 'kk', 'uz', 'az', 'ky', 'tg', 'tk', 'hy', 'ka', 'mo'];
  if (cis.includes(lang)) return 'ru';
  return T[lang] ? lang : 'en';
}

/* ===== EXPOSE helper for script.js form handler ===== */
window.getI18n = key => {
  const lang = localStorage.getItem('lang') || detectLang();
  return (T[lang] && T[lang][key]) || (T.en && T.en[key]) || key;
};

/* ===== BOOT ===== */
document.addEventListener('DOMContentLoaded', () => {
  initHeaderSwitcher();
  const saved = localStorage.getItem('lang');
  const lang = saved || detectLang();
  if (!saved) localStorage.setItem('lang', lang);
  applyLang(lang);
});
